import {
  Box,
  Button,
  FormControl,
  FormLabel,
  Grid,
  Input,
  Text,
  Textarea,
} from "@chakra-ui/react";
import React, { useState } from "react";

import AdminNavTop from "../AdminNavTop";
import { useDispatch, useSelector } from "react-redux";
import { addProduct } from "../../Redux/AdminReducer/action";
import { useNavigate } from "react-router-dom";

const AddCourse = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();

  let obj = {
    title: "",
    description: "",
    category: "",
    price: "",
    img:""
  };

  const [detail, setDetail] = useState(obj);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setDetail((prev) => {
      return { ...prev, [name]: value };
    });
  };
  const handleSubmit = () => {
    dispatch(addProduct(detail));

    alert("Course Added Successfully");
    navigate("/admin/courses");
  };

  return (
  <Box bg="#f7f9fa" minH="100vh" p={6}>
    <AdminNavTop />

    <Box
      maxW="700px"
      mx="auto"
      mt="80px"
      bg="white"
      p={8}
      borderRadius="lg"
      boxShadow="lg"
    >
      {/* TITLE */}
      <Text fontSize="2xl" fontWeight="bold" mb={6}>
        Create New Course
      </Text>

      {/* FORM */}
      <FormControl mb={4}>
        <FormLabel>Title</FormLabel>
        <Input
          placeholder="Enter course title"
          name="title"
          value={detail.title}
          onChange={handleChange}
          _focus={{ borderColor: "#A435F0", boxShadow: "0 0 0 1px #A435F0" }}
        />
      </FormControl>

      <FormControl mb={4}>
        <FormLabel>Description</FormLabel>
        <Textarea
          placeholder="Enter course description"
          name="description"
          value={detail.description}
          onChange={handleChange}
          _focus={{ borderColor: "#A435F0" }}
        />
      </FormControl>

      <FormControl mb={4}>
        <FormLabel>Category</FormLabel>
        <Input
          placeholder="Enter category"
          name="category"
          value={detail.category}
          onChange={handleChange}
          _focus={{ borderColor: "#A435F0" }}
        />
      </FormControl>

      <FormControl mb={4}>
        <FormLabel>Price</FormLabel>
        <Input
          type="number"
          placeholder="Enter price"
          name="price"
          value={detail.price}
          onChange={handleChange}
          _focus={{ borderColor: "#A435F0" }}
        />
      </FormControl>

      <FormControl mb={6}>
        <FormLabel>Thumbnail URL</FormLabel>
        <Input
          placeholder="Paste image URL"
          name="img"
          value={detail.img}
          onChange={handleChange}
          _focus={{ borderColor: "#A435F0" }}
        />
      </FormControl>

      {/* BUTTON */}
      <Button
        bg="#A435F0"
        color="white"
        size="lg"
        w="100%"
        _hover={{ bg: "#8710d8" }}
        onClick={handleSubmit}
      >
        Create Course
      </Button>
    </Box>
  </Box>
);
};

export default AddCourse;
